private fun entryTime(entry: HomeEntry): LocalTime {
    val parts = entry.time.split(":")
    val h = parts.getOrNull(0)?.toIntOrNull() ?: 0
    val m = parts.getOrNull(1)?.toIntOrNull() ?: 0
    return LocalTime.of(h, m)
}

