    // ── JSON response parsing ────────────────────────────────────────────────
    // org.json is not available in JVM unit tests, so we build the JSON strings
    // using a tiny helper that mimics the format the Anthropic API returns.

    private fun anthropicJson(vararg blocks: Pair<String, String>): String {
        val contentArray = blocks.joinToString(",") { (type, value) ->
            if (type == "text") """{"type":"text","text":"$value"}"""
            else """{"type":"$type","$type":"$value"}"""
        }
        return """{"content":[$contentArray]}"""
    }

    @Test
    fun parseTextContent_singleTextBlock_returnsText() {
        val json = anthropicJson("text" to "You have CS 101 at 9 AM today.")
        assertEquals("You have CS 101 at 9 AM today.", AgentRepository.parseTextContent(json))
    }

    @Test
    fun parseTextContent_trailingWhitespaceTrimmed() {
        // Build JSON manually to embed leading/trailing spaces in the value
        val json = """{"content":[{"type":"text","text":"  Hello!  "}]}"""
        assertEquals("Hello!", AgentRepository.parseTextContent(json))
    }

