package com.example.combined_schedule.data

import com.example.combined_schedule.BuildConfig
import com.google.gson.JsonArray
import com.google.gson.JsonObject
import com.google.gson.JsonParser
import java.io.OutputStreamWriter
import java.net.HttpURLConnection
import java.net.URL

object AgentRepository {

    private const val API_URL = "https://api.anthropic.com/v1/messages"
    private const val MODEL = "claude-opus-4-6"

    /**
     * Ask the AI agent a question about the user's schedule and assignments.
     * Returns the agent's text reply, or an error message on failure.
     */
    fun ask(
        query: String,
        entries: List<HomeEntry>,
        works: List<Work>
    ): String {
        val apiKey = BuildConfig.ANTHROPIC_API_KEY
        if (apiKey.isBlank() || apiKey == "YOUR_KEY_HERE") return noKeyMessage()

        val systemPrompt = buildSystemPrompt(entries, works)
        val body = buildRequestBody(systemPrompt, query)

        val conn = URL(API_URL).openConnection() as HttpURLConnection
        conn.requestMethod = "POST"
        conn.setRequestProperty("Content-Type", "application/json")
        conn.setRequestProperty("x-api-key", apiKey)
        conn.setRequestProperty("anthropic-version", "2023-06-01")
        conn.connectTimeout = 15_000
        conn.readTimeout = 15_000
        conn.doOutput = true

        OutputStreamWriter(conn.outputStream, Charsets.UTF_8).use { it.write(body) }

        val responseCode = conn.responseCode
        val responseText = if (responseCode == 200) {
            conn.inputStream.bufferedReader().readText()
        } else {
            conn.errorStream?.bufferedReader()?.readText() ?: "HTTP $responseCode"
        }

        if (responseCode != 200) return "Agent error ($responseCode). Check your API key."

        return parseTextContent(responseText)
    }

    internal fun buildSystemPrompt(entries: List<HomeEntry>, works: List<Work>): String {
        val scheduleLines = if (entries.isEmpty()) {
            "No schedule entries today."
        } else {
            entries.joinToString("\n") { e ->
                "- ${e.title} at ${e.time}" +
                    (if (e.location.isNotEmpty()) " (${e.location})" else "") +
                    " [${e.daysOfWeek.joinToString(",")}]"
            }
        }

        val pendingWorks = works.filter { !it.isCompleted }
        val workLines = if (pendingWorks.isEmpty()) {
            "No pending assignments."
        } else {
            pendingWorks.joinToString("\n") { w ->
                "- \"${w.title}\" for ${w.courseTitle}" +
                    (if (w.dueDate.isNotEmpty()) " due ${w.dueDate}" else "")
            }
        }

        return """You are a helpful assistant embedded in a student schedule app.
You have access to the student's current schedule entries and pending assignments.
Answer questions concisely — 1-3 sentences. If the student asks about something
not in their data, say so briefly.

SCHEDULE ENTRIES:
$scheduleLines

PENDING ASSIGNMENTS:
$workLines"""
    }

    internal fun buildRequestBody(systemPrompt: String, userQuery: String): String {
        val message = JsonObject().apply {
            addProperty("role", "user")
            addProperty("content", userQuery)
        }
        val messages = JsonArray().apply { add(message) }
        return JsonObject().apply {
            addProperty("model", MODEL)
            addProperty("max_tokens", 512)
            addProperty("system", systemPrompt)
            add("messages", messages)
        }.toString()
    }

    internal fun parseTextContent(json: String): String {
        val root = JsonParser.parseString(json).asJsonObject
        val content = root.getAsJsonArray("content")
        for (element in content) {
            val block = element.asJsonObject
            if (block.get("type")?.asString == "text") {
                return block.get("text").asString.trim()
            }
        }
        return "No response from agent."
    }

    private fun noKeyMessage() =
        "AI agent not configured. Add your Anthropic API key to local.properties."
}

